head.script:
scwin.tr_actionKind; //조회/수정 구분
scwin.updBtnYn = false; // 수정 버튼 클릭 시 row 값 비교를 위한
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

    const nowDate = new Date();
    const nowYyyy = nowDate.getFullYear();
    const nowMm = String(nowDate.getMonth() + 1).padStart(2, '0');
    const nowDd = String(nowDate.getDate()).padStart(2, '0');

    scwin.nowYYYYMMDD = nowYyyy + nowMm + nowDd;

    acb_lc_lineCd.setSelectedIndex(0);
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $c.gus.cfDisableObjects(tb_retrieveData);
	$c.gus.cfDisableBtnOnly([btn_update, btn_cancel, btn_save]);
    udc_doIssueDdDt.setInitDate(scwin.nowYYYYMMDD, scwin.nowYYYYMMDD);
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    $c.gus.cfInitObjects(tb_queryList, null);

    udc_doIssueDdDt.setInitDate(scwin.nowYYYYMMDD, scwin.nowYYYYMMDD);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = async function (e) {
    scwin.updBtnYn = false;
    ds_list.undoAll();
    let ret1 = await $c.gus.cfValidate(doIssueDdStDt.getValue());
    let ret2 = await $c.gus.cfValidate(doIssueDdEndDt.getValue());
    if( ret1 || ret2 ){
        return;
    }

    let afterDate = $c.gus.cfIsAfterDate(doIssueDdStDt.getValue(), doIssueDdEndDt.getValue());
    if( !afterDate ) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        doIssueDdStDt.focus();
        return;
    }

    let ret3 = await $c.gus.cfValidate([tb_queryList]);
    if( !ret3 ) {
        return;
    }

    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        totalRows.setValue(ds_list.getRowCount()); // 총 조회건수 표시
        scwin.cancelDisable();
        //조회결과가 0인경우
        if( ds_list.getRowCount() == 0 ) {
            $c.gus.cfDisableBtnOnly([btn_update, btn_save, btn_cancel]);
            $c.gus.cfAlertMsg(MSG_CM_ERR_003); //조회결과가 존재하지 않습니다.
            return false;
        } else {
            gr_list.setFocusedCell(0, 0);
            $c.gus.cfEnableBtnOnly([btn_update]);
            $c.gus.cfDisableBtnOnly([btn_cancel, btn_save]);
        }
    }
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.btn_update_onclick = function (e) {
    scwin.tr_actionKind = "UPDATE";
    scwin.updBtnYn = true;
    $c.gus.cfEnableObjects([ica_ed_cntrCrryoutCloseDt, ica_ed_cntrRtrnDt, ed_transCoId, acb_lc_selfYn]); //cal_crryoutCloseDd, cal_cntrCrryoutCloseDt - 달력 버튼

    //버튼제어
    $c.gus.cfEnableBtnOnly([btn_cancel, btn_save]);
    // $c.gus.cfDisableBtnOnly([btn_update]); //btn_create
};

scwin.sbm_update_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        $c.gus.cfAlertMsg(MSG_CM_INF_001); // 성공적으로 저장하였습니다
        $c.gus.cfDisableObjects(tb_retrieveData);
        scwin.btn_retrieve_onclick();
    }
};

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.btn_cancel_onclick = function (e) {
    var row = ds_list.getRowPosition();
    ds_list.undoAll();
    scwin.cancelDisable();
    //조회된 결과값여부에 따라 버튼 처리
    if( ds_list.getRowCount() > 0 && ds_list.getRowPosition() >= 0 ) {
        $c.gus.cfEnableBtnOnly([btn_update]);
        $c.gus.cfDisableBtnOnly([btn_save, btn_cancel]);
    } else {
        $c.gus.cfDisableBtnOnly([btn_update, btn_save, btn_cancel]);
    }
    gr_list.setFocusedCell(row, 0);
};

scwin.cancelDisable = function (e) {
    //폼잠금여부
    $c.gus.cfDisableObjects([
        ed_blNo, ed_doNo2, ica_ed_doIssueDd, acb_lc_selfYn //, cal_doIssueDd
        , ed_transCoId, ica_ed_cntrCrryoutCloseDt //, cal_crryoutCloseDd, cal_cntrCrryoutCloseDt
        , ica_ed_cntrRtrnDt, acb_lc_doOutbrShpCo, ed_txt_callsignCd, ed_txt_vsslNm, ed_txt_vsslPortcnt
        , ica_ed_vsslArrvlportDtm, ed_cntrNo2, ed_txt_cntrNrm, ed_txt_mrn //, cal_vsslArrvlportDtm
        , ed_txt_msn, ed_txt_dsmbrkPlcCd, ed_txt_dropPort, ed_txt_dchrPort
        , ed_txt_sendMchtNm1, ed_txt_cntMchtNm, ed_txt_rmkDesc
    ]);
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
    //Mandatory 항목이 누락하지 않았는지 체크한다.
    let validate = await $c.gus.cfValidate([tb_retrieveData]);
    console.log("### btn_save_onclick : "+validate);
    if ( !validate ) {
        return;
    }

    let row = ds_list.getRowPosition();
    let confirm = await $c.win.confirm("저장하시겠습니까?")
    if( confirm ) {
        //수정 + 저장
        dma_list.set("cntrCrryoutCloseDt" 	, ds_list.getCellData(row, "cntrCrryoutCloseDt"));
        dma_list.set("cntrRtrnDt" 			, ds_list.getCellData(row, "cntrRtrnDt"));
        dma_list.set("doNo" 				, ds_list.getCellData(row, "doNo"));
        dma_list.set("cntrNo" 				, ds_list.getCellData(row, "cntrNo"));
        dma_list.set("selfYn" 				, ds_list.getCellData(row, "selfYn"));
        dma_list.set("transCoId" 			, ds_list.getCellData(row, "transCoId"));
        //저장
        dma_list.set("blNo"				    , ds_list.getCellData(row, "blNo"));
        dma_list.set("doIssueDd"			, ds_list.getCellData(row, "doIssueDd"));
        dma_list.set("callsignCd"			, ed_txt_callsignCd.getValue().toUpperCase());
        dma_list.set("doOutbrShpCo"		    , acb_lc_doOutbrShpCo.getValue());
        dma_list.set("vsslNm"				, ed_txt_vsslNm.getValue().toUpperCase());
        dma_list.set("vsslPortcnt"		    , ed_txt_vsslPortcnt.getValue().toUpperCase());
        dma_list.set("vsslArrvlportDtm"	    , ica_ed_vsslArrvlportDtm.getValue());
        dma_list.set("cntrNrm"			    , ed_txt_cntrNrm.getValue().toUpperCase());
        dma_list.set("mrn"				    , ed_txt_mrn.getValue().toUpperCase());
        dma_list.set("msn"				    , ed_txt_msn.getValue());
        dma_list.set("dsmbrkPlcCd"		    , ds_list.getCellData(row, "dsmbrkPlcCd").toUpperCase());
        dma_list.set("dropPort"			    , ed_txt_dropPort.getValue().toUpperCase());
        dma_list.set("dchrPort"			    , ed_txt_dchrPort.getValue().toUpperCase());
        dma_list.set("sendMchtNm1"		    , ed_txt_sendMchtNm1.getValue().toUpperCase());
        dma_list.set("cntMchtNm"			, ed_txt_cntMchtNm.getValue().toUpperCase());
        dma_list.set("rmkDesc"			    , ed_txt_rmkDesc.getValue());

        if (scwin.tr_actionKind == "INSERT") {
            $c.sbm.execute(sbm_insert);  //TODO : [신규] - btn_create 버튼 ASIS 에서는 주석처리 되어있음.
        }
        else if (scwin.tr_actionKind == "UPDATE") {
            $c.sbm.execute(sbm_update);
        }
    }
};

scwin.sbm_insert_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 )
    {
        $c.gus.cfAlertMsg(MSG_CM_INF_001); // 성공적으로 저장하였습니다
        $c.gus.cfDisableObjects(tb_retrieveData);
        scwin.btn_retrieve_onclick();
    }
};

scwin.ds_list_onrowpositionchange = function (info) {
    let row = info.newRowIndex;
    let vCountRow = ds_list.getRowCount();
    let vRowPosition = ds_list.getRowPosition();
    let vRowStatus = ds_list.getRowStatusValue(vRowPosition); //rowIndex에 해당하는 행의 상태 코드를 숫자로 반환 (초기상태:0, 갱신:1, 삽입:2, 삭제:3, 삽입 후 삭제:4)
    let vChgCount = 0;
    let vChgRow = 0;

    for(let i=0; i < vCountRow;i++){
        let vCurRowStatus = ds_list.getRowStatus(i);

        if(vCurRowStatus == "C" || vCurRowStatus=="U"){
            vChgCount++;
            vChgRow = i;
            break; //신규 신규 만들면 우리는 처리상 이걸 한번 더 탄다. 그러면  row != vChgRow 안걸림
        }
    }

    // 신규등록시 로우가 변경되었을 경우
    if(vChgCount > 0 && row != vChgRow){
        $c.win.alert("신규등록이나 수정사항을 저장하신 후에  이동해주시기 바랍니다.");
        ds_list.setRowPosition(vChgRow);
        gr_list.setFocusedCell(vChgRow, 0);

        for(let i=vCountRow-1; i >-1; i--){
            let vCurRowStatus = ds_list.getRowStatus(i);
            if( vCurRowStatus=="U"){
                if(i != vChgRow ){
                     ds_list.undoRow(i);
                }
            } else if ( vCurRowStatus == "C") {
                if(i != vChgRow ){
                     ds_list.removeRow(i);
                }
            }
        }
        return false;
    }
    //수정시 로우가 변경되었을 경우
    if( vRowStatus == 0 ) {
        $c.gus.cfDisableObjects(tb_retrieveData);
        $c.gus.cfDisableBtnOnly([btn_cancel, btn_save]);
        //$c.gus.cfEnableBtnOnly([btn_update]);
    } else if ( vRowStatus == 1 ) {
        // $c.gus.cfDisableBtnOnly([btn_update]); //btn_create
        //$c.gus.cfEnableBtnOnly([btn_cancel, btn_save]);
    }
};
